model = genai.GenerativeModel("gemini-3-flash")
chat = model.start_chat()

# Send message with streaming
response = chat.send_message(
    "Analyze this code for bugs",
    stream=True,
    generation_config={"thinking": {"type": "enabled", "budget_tokens": 10000}}
)

for chunk in response:
    print(chunk.text, end="", flush=True)

import inspect

def search_weather(location: str, unit: str = "C") -> dict:
    """Search weather for a location.

    Args:
        location: City name
        unit: Temperature unit (C or F)
    """
    return {"temp": 25, "unit": unit, "location": location}

model = genai.GenerativeModel(
    "gemini-3-flash",
    tools=[search_weather]
)

response = model.generate_content(
    "What's the weather in Paris?",
    tool_config={"function_calling_config": {"mode": "ANY"}}
)

if response.tool_calls:
    for call in response.tool_calls:
        result = search_weather(**call.args)
        # Send result back to model
        response = model.generate_content([
            "What's the weather in Paris?",
            response,
            {"role": "user", "parts": [{"function_response": {"name": "search_weather", "response": result}}]}
        ])
